// lit
import { LitElement, html, TemplateResult, CSSResultArray } from 'lit';
import { property } from 'lit/decorators.js';
// styles
import { styles } from './styles/index.styles';
// types
import { Fit, IMcLabel, LabelPosition } from './types';

export type { IMcLabel } from './types';

/**
 * Purpose: Component for displaying labels for form elements and other UI components.
 * Category: Forms
 * When to use: When you need to display a label for a form element or UI component.
 * When not to use: When you don't need a label or when using a different labeling approach.
 * Works with components: mc-checkbox-group, mc-date-picker, mc-file-upload, mc-input-date, mc-input-time, mc-input, mc-multi-select, mc-number-stepper, mc-radio-group, mc-select-native, mc-select, mc-switch-group, mc-textarea, mc-typeahead-multi-select, mc-typeahead
 * Alternative component names: Form Label, Input Label
 *
 * @element `mc-label`
 *
 * @slot - The default slot for the label text. Used to display custom text/icon
 *
 * @csspart `label` - for changing visuals of label
 */
export class McLabel extends LitElement implements IMcLabel {
  @property({ type: String })
  public fit: Fit = 'medium';

  @property({ type: Boolean })
  public hiddenlabel = false;

  @property({ type: String })
  public label = 'Label';

  @property({ type: String })
  public labelposition: LabelPosition = 'top';

  public static get styles(): CSSResultArray {
    return styles;
  }

  /* render */
  protected render(): TemplateResult {
    return html`<slot part="label" class="mc-label ${this.fit} ${this.labelposition}">${this.label}</slot>`;
  }
}

declare global {
  interface HTMLElementTagNameMap {
    'mc-label': McLabel;
  }
}

customElements.get('mc-label') || customElements.define('mc-label', McLabel);
